# agents/vision.py# Vision Agent# OpenAI-compatible local vision client for LM Studio / vLLM / Ollama proxy## Supports:# - Local image files# - Remote image URLs# - OCR# - UI analysis# - Code screenshot review# - Chart analysis## Usage:#   python agents/vision.py image.png#   python agents/vision.py image.png "What errors are visible?"#   python agents/vision.py https://example.com/image.jpgimport sysimport base64import mimetypesfrom pathlib import Pathimport requestsfrom rich.console import Consolefrom core.config_loader import cfgconsole = Console()SYSTEM = """You are a visual analysis expert.Responsibilities:- Describe images accurately- Read and transcribe text- Analyze UI screenshots- Review code screenshots- Analyze charts and diagrams- Explain technical visuals clearlyRules:- Be detailed and specific- Mention anything unusual- Explain layout structure- For screenshots include visible errors- For code screenshots transcribe code accurately"""DEFAULT_PROMPT = "Describe this image in detail."# =========================================================# HELPERS# =========================================================def encode_image(image_path: str) -> str:    with open(image_path, "rb") as f:        return base64.b64encode(f.read()).decode("utf-8")def get_mime_type(image_path: str) -> str:    mime, _ = mimetypes.guess_type(image_path)    return mime or "image/png"def build_image_content_from_file(image_path: str) -> list:    image_data = encode_image(image_path)    mime_type = get_mime_type(image_path)    return [        {            "type": "image_url",            "image_url": {                "url": f"data:{mime_type};base64,{image_data}"            }        }    ]def build_image_content_from_url(image_url: str) -> list:    return [        {            "type": "image_url",            "image_url": {                "url": image_url            }        }    ]# =========================================================# CORE VISION CALL# =========================================================def call_vision(    image_content: list,    prompt: str = DEFAULT_PROMPT) -> str:    model_name = getattr(        cfg,        "vision_model",        "qwen/qwen2.5-vl-7b-instruct"    )    lm_url = getattr(        cfg,        "lm_studio_url",        "http://localhost:1234/v1"    ).rstrip("/")    payload = {        "model": model_name,        "messages": [            {                "role": "system",                "content": SYSTEM            },            {                "role": "user",                "content": image_content + [                    {                        "type": "text",                        "text": prompt                    }                ]            }        ],        "temperature": 0.3,        "max_tokens": 2000,        "stream": False    }    try:        console.print(            f"[cyan]Using model:[/cyan] {model_name}"        )        response = requests.post(            f"{lm_url}/chat/completions",            json=payload,            timeout=(15, 300)        )        if response.status_code != 200:            console.print(                f"[red]HTTP {response.status_code}[/red]"            )            console.print(response.text)            return "[ERROR] Vision API request failed."        data = response.json()        if "choices" not in data:            console.print(data)            return "[ERROR] Invalid response from API."        return (            data["choices"][0]            ["message"]            ["content"]        )    except requests.exceptions.ConnectionError:        return (            "[ERROR] Could not connect to LM Studio.\n"            "Make sure the local server is running."        )    except requests.exceptions.Timeout:        return (            "[ERROR] Vision request timed out."        )    except Exception as e:        return f"[ERROR] {type(e).__name__}: {e}"# =========================================================# FILE ANALYSIS# =========================================================def vision_analyze_file(    image_path: str,    prompt: str = DEFAULT_PROMPT) -> str:    path = Path(image_path)    if not path.exists():        return f"[ERROR] File not found: {image_path}"    console.print(        f"[cyan]Analyzing image:[/cyan] {image_path}"    )    try:        content = build_image_content_from_file(            image_path        )        return call_vision(content, prompt)    except Exception as e:        return f"[ERROR] Failed to analyze image: {e}"# =========================================================# URL ANALYSIS# =========================================================def vision_analyze_url(    image_url: str,    prompt: str = DEFAULT_PROMPT) -> str:    console.print(        f"[cyan]Analyzing URL:[/cyan] {image_url}"    )    content = build_image_content_from_url(        image_url    )    return call_vision(content, prompt)# =========================================================# SPECIALIZED HELPERS# =========================================================def vision_describe_screenshot(    image_path: str) -> str:    return vision_analyze_file(        image_path,        (            "This is a screenshot.\n"            "Describe the application layout.\n"            "List all visible text.\n"            "Identify warnings, errors, or issues.\n"            "Suggest UI and UX improvements."        )    )def vision_read_code_screenshot(    image_path: str) -> str:    return vision_analyze_file(        image_path,        (            "This is a code screenshot.\n"            "Identify the programming language.\n"            "Transcribe the code accurately.\n"            "Explain what the code does.\n"            "Identify bugs or issues.\n"            "Suggest improvements."        )    )def vision_analyze_chart(    image_path: str) -> str:    return vision_analyze_file(        image_path,        (            "Analyze this chart.\n"            "Identify chart type.\n"            "Read labels and values.\n"            "Describe trends.\n"            "Summarize findings."        )    )# =========================================================# MAIN ENTRY# =========================================================if __name__ == "__main__":    if len(sys.argv) < 2:        console.print(            "\n[yellow]Usage:[/yellow]"        )        console.print(            "python agents/vision.py <image_path> [question]"        )        sys.exit(1)    target = sys.argv[1]    question = (        " ".join(sys.argv[2:])        if len(sys.argv) > 2        else DEFAULT_PROMPT    )    console.print(        "\n[bold cyan]=== Vision Agent ===[/bold cyan]\n"    )    if target.startswith("http://") or target.startswith("https://"):        result = vision_analyze_url(            target,            question        )    else:        result = vision_analyze_file(            target,            question        )    console.print("\n[bold green]Result:[/bold green]\n")    console.print(result)